INSERT INTO incidents VALUES(7,'John Thivy',replace('John Thivy came back into the Cafe and started telling at Lisa in the kitchen. Accusing her of talking about him  behind his back,  also  accusing Lisa of giving them up. Alot of yelling at Lisa by John. John was close to Lisa when yelling. Suggested Lisa leave by different way ut she said she was fine.\n','\n',char(10)),'2025-09-17 02:50:13.783026','2025-09-17 02:50:13.783026');
INSERT INTO incidents VALUES(11,'Burn to hand',replace('JASMINE burnt her hand when lighting her cigarette. She was sitting in the courtyard. \nBlister developed. Cold water provided to soak hand. Jasmine left with cool cloth on hand.','\n',char(10)),'2026-02-21 02:40:34.520005','2026-02-21 02:40:34.520005');
