PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "incidents" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "title" varchar, "description" varchar, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
CREATE TABLE IF NOT EXISTS "people" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar NOT NULL, "email" varchar, "phone" varchar, "volunteer" boolean DEFAULT 0, "present" boolean DEFAULT 0, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "archived" boolean DEFAULT 0 NOT NULL /*application='Buss'*/);
CREATE TABLE IF NOT EXISTS "sign_ins" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "left_at" datetime(6), "arrived_at" datetime(6), "person_id" integer NOT NULL, "volunteer" boolean DEFAULT 0 NOT NULL /*application='Buss'*/, "activity" boolean DEFAULT 0 NOT NULL /*application='Buss'*/, CONSTRAINT "fk_rails_f32d06a6c5"
FOREIGN KEY ("person_id")
  REFERENCES "people" ("id")
);
CREATE TABLE IF NOT EXISTS "schema_migrations" ("version" varchar NOT NULL PRIMARY KEY);
CREATE TABLE IF NOT EXISTS "ar_internal_metadata" ("key" varchar NOT NULL PRIMARY KEY, "value" varchar, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
CREATE TABLE IF NOT EXISTS "notes" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "info" integer, "amount" integer, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
DELETE FROM sqlite_sequence;
CREATE INDEX "index_sign_ins_on_person_id" ON "sign_ins" ("person_id") /*application='Buss'*/;
CREATE UNIQUE INDEX "index_people_on_name" ON "people" ("name") /*application='Buss'*/;
CREATE INDEX "index_people_on_archived" ON "people" ("archived") /*application='Buss'*/;
COMMIT;
